1	//! Agent Nervous System daemon entry point.
2	//!
3	//! Starts two servers:
4	//! - gRPC server on loopback:50051 (internal Python/TS clients)
5	//! - Gateway on loopback:50052 (external AI agents — MCP, REST, WS)
6	//!
7	//! Both run concurrently. Chromium instances are cleaned up on exit
8	//! via RAII drop guards. Ctrl+C triggers graceful shutdown.
9	
10	use std::net::{IpAddr, Ipv4Addr, SocketAddr};
11	use std::path::PathBuf;
12	
13	use ans_ipc::IpcServer;
14	use clap::Parser;
15	use tracing_subscriber::EnvFilter;
16	
17	#[derive(Parser)]
18	#[command(name = "ans-daemon", version, about = "Agent Nervous System daemon")]
19	struct Cli {
20	    /// gRPC port to bind on loopback
21	    #[arg(long, default_value = "50051")]
22	    grpc_port: u16,
23	
24	    /// Gateway port to bind on loopback
25	    #[arg(long, default_value = "50052")]
26	    gateway_port: u16,
27	
28	    /// Gateway bind address (use 0.0.0.0 for Docker, 127.0.0.1 for local)
29	    #[arg(long, default_value = "127.0.0.1")]
30	    gateway_bind: IpAddr,
31	
32	    /// Path to ans.toml configuration file
33	    #[arg(long, default_value = "ans.toml")]
34	    config: PathBuf,
35	
36	    /// Path to nerves/ directory (Python intelligence layer)
37	    #[arg(long, default_value = "nerves")]
38	    nerves_dir: PathBuf,
39	
40	    /// Number of Chromium instances to pre-warm (default 2, 0 to disable)
41	    #[arg(long, default_value = "2")]
42	    prewarm: usize,
43	}
44	
45	#[tokio::main]
46	async fn main() {
47	    if let Err(e) = color_eyre::install() {
48	        eprintln!("Failed to install color-eyre panic handler: {e}");
49	        std::process::exit(1);
50	    }
51	
52	    let cli = Cli::parse();
53	
54	    tracing_subscriber::fmt()
55	        .with_env_filter(
56	            EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("ans=debug,info")),
57	        )
58	        .init();
59	
60	    tracing::info!(version = env!("CARGO_PKG_VERSION"), "ans-daemon starting");
61	
62	    if let Some(cfg) = load_config(&cli.config) {
63	        tracing::info!(?cfg, "Config loaded");
64	    } else {
65	        tracing::info!("No config file found, using defaults");
66	    }
67	
68	    // ── Start gRPC server in background ──────────────────────────────
69	    let nerves_abs = if cli.nerves_dir.is_absolute() {
70	        cli.nerves_dir.clone()
71	    } else {
72	        std::env::current_dir().unwrap_or_default().join(&cli.nerves_dir)
73	    };
74	    let server = IpcServer::new()
75	        .with_nerves_dir(nerves_abs)
76	        .with_pool_size(cli.prewarm)
77	        .with_grpc_port(cli.grpc_port);
78	    let goal_store = server.goal_store(); // clone before server moves into spawn
79	    let sessions = server.session_manager(); // clone before server moves into spawn
80	    let goals = server.goal_manager(); // clone for error recovery resume
81	    let grpc_addr = SocketAddr::new(IpAddr::V4(Ipv4Addr::LOCALHOST), cli.grpc_port);
82	
83	    let grpc_handle = tokio::spawn(async move {
84	        if let Err(e) = server.serve(grpc_addr).await {
85	            tracing::error!(%e, "gRPC server exited with error");
86	        }
87	    });
88	
89	    // Give the gRPC server a moment to bind before starting the gateway
90	    tokio::time::sleep(std::time::Duration::from_millis(300)).await;
91	
92	    // ── Start gateway ────────────────────────────────────────────────
93	    let gw_addr = SocketAddr::new(cli.gateway_bind, cli.gateway_port);
94	
95	    let gw_handle = match ans_gateway::Gateway::init(
96	        cli.grpc_port,
97	        Some(goal_store),
98	        Some(sessions),
99	        Some(goals),
100	    )
101	    .await
102	    {
103	        Ok(gateway) => {
104	            tracing::info!("Gateway starting on {}", gw_addr);
105	            tokio::spawn(async move {
106	                if let Err(e) = gateway.serve(gw_addr).await {
107	                    tracing::error!(%e, "Gateway exited with error");
108	                }
109	            })
110	        }
111	        Err(e) => {
112	            tracing::warn!(%e, "Gateway failed to initialize — running gRPC-only");
113	            // Still wait for gRPC server
114	            let _ = grpc_handle.await;
115	            return;
116	        }
117	    };
118	
119	    // ── Wait for shutdown ────────────────────────────────────────────
120	    tokio::select! {
121	        _ = tokio::signal::ctrl_c() => {
122	            tracing::info!("Shutdown signal received");
123	        }
124	        _ = grpc_handle => {
125	            tracing::warn!("gRPC server exited unexpectedly");
126	        }
127	        _ = gw_handle => {
128	            tracing::warn!("Gateway exited unexpectedly");
129	        }
130	    }
131	
132	    tracing::info!("ans-daemon shut down cleanly");
133	}
134	
135	fn load_config(path: &PathBuf) -> Option<toml::Value> {
136	    let content = std::fs::read_to_string(path).ok()?;
137	    toml::from_str(&content).ok()
138	}
