149	    /// Start the gRPC server and block until shutdown signal received.
150	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
151	        let grpc_port = self.grpc_port;
152	        let svc = AgentNervousSystemServer {
153	            sessions: self.sessions,
154	            goals: self.goals,
155	            events: self.events,
156	            decisions: self.decisions,
157	            budget: self.budget,
158	            signal_router: self.signal_router,
159	            metrics: self.metrics,
160	            nerves_dir: self.nerves_dir,
161	            grpc_port,
162	        };
163	
164	        tracing::info!("gRPC server starting on {}", addr);
165	
166	        // SO_REUSEADDR prevents "address already in use" on restart
167	        // (Windows: allows bind to TIME_WAIT port; Unix: same + TIME_WAIT reuse)
168	        let socket = socket2::Socket::new(
169	            socket2::Domain::IPV4,
170	            socket2::Type::STREAM,
171	            Some(socket2::Protocol::TCP),
172	        )?;
173	        socket.set_reuse_address(true)?;
174	        socket.bind(&socket2::SockAddr::from(addr))?;
175	        socket.listen(128)?;
176	        socket.set_nonblocking(true)?;
177	
178	        let listener = tokio::net::TcpListener::from_std(socket.into())?;
179	        let incoming = tokio_stream::wrappers::TcpListenerStream::new(listener);
180	
181	        Server::builder()
182	            .add_service(generated::AgentNervousSystemServer::new(svc))
183	            .serve_with_incoming(incoming)
184	            .await?;
185	
186	        Ok(())
187	    }
188	}
