430	    async fn create_goal(
431	        &self,
432	        request: Request<CreateGoalRequest>,
433	    ) -> Result<Response<GoalState>, Status> {
434	        let req = request.into_inner();
435	        let state = self
436	            .goals
437	            .create_goal(&req.description, &req.context, req.max_steps as u32)
438	            .map_err(|e| Status::internal(e.to_string()))?;
439	
440	        self.metrics.inc_goals(1);
441	
442	        // Spawn Python AgentLoop in background
443	        let goal_id = state.goal_id.to_string();
444	        let goal_uuid = state.goal_id;
445	        let description = state.description.clone();
446	        let nerves_dir = self.nerves_dir.clone();
447	        let goals = self.goals.clone();
448	        let grpc_port = self.grpc_port;
449	        tokio::spawn(async move {
450	            // Auto-detect venv Python relative to nerves_dir
451	            let python = if let Some(ref dir) = nerves_dir {
452	                let venv_python = dir.join(".venv").join("Scripts").join("python.exe");
453	                if venv_python.exists() {
454	                    venv_python
455	                } else {
456	                    let unix_venv = dir.join(".venv").join("bin").join("python");
457	                    if unix_venv.exists() { unix_venv } else { std::path::PathBuf::from("python") }
458	                }
459	            } else {
460	                std::path::PathBuf::from("python")
461	            };
462	
463	            let mut cmd = tokio::process::Command::new(&python);
464	            cmd.args(["-m", "ans_nerves", "run", "--goal-id", &goal_id, &description])
465	                .kill_on_drop(true)
466	                .env("ANS_GRPC_PORT", grpc_port.to_string())
467	                .env("ANS_GRPC_HOST", "127.0.0.1");
468	            if let Some(ref dir) = nerves_dir {
469	                cmd.current_dir(dir);
470	            }
471	            match cmd.output().await {
472	                Ok(output) => {
473	                    if output.status.success() {
474	                        tracing::info!(%goal_id, "Python AgentLoop completed");
475	                    } else {
476	                        let stderr = String::from_utf8_lossy(&output.stderr);
477	                        tracing::error!(%goal_id, %stderr, "Python AgentLoop failed");
478	                        let _ = goals.update_progress(goal_uuid, 0.0, ans_core::goal::GoalStatus::Failed, None);
479	                    }
480	                }
481	                Err(e) => {
482	                    tracing::error!(%goal_id, error=%e, "Failed to spawn Python AgentLoop");
483	                    let _ = goals.update_progress(goal_uuid, 0.0, ans_core::goal::GoalStatus::Failed, None);
484	                }
485	            }
486	        });
487	
488	        Ok(Response::new(ans_goal::serialization::goal_state_to_proto(
489	            &state,
490	        )))
491	    }
