661	    // ── Immune System ────────────────────────────────────────────────
662	
663	    async fn classify_distractions(
664	        &self,
665	        request: Request<DistractionRequest>,
666	    ) -> Result<Response<DistractionList>, Status> {
667	        let req = request.into_inner();
668	        let url = req.url;
669	
670	        // Extract CSS class/id hints from DOM elements for distraction pattern matching
671	        let css_hints = req
672	            .dom
673	            .as_ref()
674	            .map(|dom| {
675	                dom.elements
676	                    .iter()
677	                    .flat_map(|el| {
678	                        el.attributes
679	                            .iter()
680	                            .filter(|(k, _)| *k == "class" || *k == "id")
681	                            .map(|(_, v)| v.clone())
682	                    })
683	                    .collect::<Vec<_>>()
684	                    .join(" ")
685	            })
686	            .unwrap_or_default();
687	
688	        // Extract all visible text from the distilled DOM for content scanning
689	        let dom_text = req
690	            .dom
691	            .as_ref()
692	            .map(|dom| {
693	                dom.elements
694	                    .iter()
695	                    .map(|el| el.text.as_str())
696	                    .collect::<Vec<_>>()
697	                    .join(" ")
698	            })
699	            .unwrap_or_default();
700	
701	        self.metrics.inc_immune_scans();
702	        let classifier = ans_immune::DistractionClassifier;
703	        let flags = classifier.classify(&url, &dom_text, &css_hints);
704	
705	        let distractions: Vec<_> = flags
706	            .iter()
707	            .map(ans_immune::serialization::distraction_to_proto_list_item)
708	            .collect();
709	
710	        Ok(Response::new(DistractionList {
711	            distractions,
712	            classification_time_us: 0,
713	        }))
714	    }
