716	    async fn scan_injections(
717	        &self,
718	        request: Request<InjectionScanRequest>,
719	    ) -> Result<Response<InjectionScanResult>, Status> {
720	        let req = request.into_inner();
721	
722	        self.metrics.inc_immune_scans();
723	        let detector = ans_immune::InjectionDetector;
724	        let start = std::time::Instant::now();
725	        let result = detector.scan(&req.url, &req.page_content);
726	        let scan_time_us = start.elapsed().as_micros() as i64;
727	
728	        let mut proto = ans_immune::serialization::injection_result_to_proto(&result);
729	        proto.scan_time_us = scan_time_us;
730	
731	        Ok(Response::new(proto))
732	    }
