734	    async fn check_action(
735	        &self,
736	        request: Request<ActionCheckRequest>,
737	    ) -> Result<Response<ActionCheckResponse>, Status> {
738	        let req = request.into_inner();
739	        let session_id = parse_uuid(&req.session_id, "session_id")?;
740	
741	        // Get current URL for context
742	        let url = self.sessions.get_url(session_id).await.unwrap_or_default();
743	
744	        // Build scannable text from the action itself
745	        let action = req.action.as_ref();
746	        let action_text = action.map_or(String::new(), |a| {
747	            format!("{} {} {}", a.action_type, a.selector, a.value)
748	        });
749	
750	        // Run both immune checks
751	        self.metrics.inc_immune_scans();
752	        let classifier = ans_immune::DistractionClassifier;
753	        let distractions = classifier.classify(&url, &action_text, &action_text);
754	
755	        let detector = ans_immune::InjectionDetector;
756	        let injection = detector.scan(&url, &action_text);
757	
758	        let response =
759	            ans_immune::serialization::build_action_check_response(&distractions, &injection);
760	
761	        Ok(Response::new(response))
762	    }
