965	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
966	/// Returns `None` if the `eye_name` is unrecognized or the content is missing.
967	fn proto_to_core_eye_report(
968	    proto: &ans_proto::ans::EyeReport,
969	) -> Option<ans_core::signal::EyeReport> {
970	    use ans_proto::ans::eye_report::Content;
971	
972	    let eye_name = match proto.eye_name.as_str() {
973	        "dom_reader" => EyeName::DomReader,
974	        "vision" => EyeName::Vision,
975	        "page_diff" => EyeName::PageDiff,
976	        "goal_verifier" => EyeName::GoalVerifier,
977	        "error_detector" => EyeName::ErrorDetector,
978	        _ => return None,
979	    };
980	
981	    let content = match &proto.content {
982	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
983	            elements: vec![],
984	            interactive: vec![],
985	            mode: dom
986	                .dom
987	                .as_ref()
988	                .map_or(DistillMode::AllFields, |d| match d.mode.as_str() {
989	                    "text_only" => DistillMode::TextOnly,
990	                    "input_fields" => DistillMode::InputFields,
991	                    _ => DistillMode::AllFields,
992	                }),
993	        },
994	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
995	            visible_elements: v.visible_elements.clone(),
996	            overlays: v.overlays.clone(),
997	            blocked_regions: v.blocked_regions.clone(),
998	            page_type: v.page_type.clone(),
999	            anomalies: v.anomalies.clone(),
1000	            raw_response: v.raw_response.clone(),
1001	        },
1002	        Some(Content::Diff(d)) => {
1003	            let diff_report = d.diff.as_ref();
1004	            EyeReportContent::DiffReport {
1005	                added: diff_report.map_or(vec![], |r| {
1006	                    r.added.iter().map(|e| e.selector.clone()).collect()
1007	                }),
1008	                removed: diff_report.map_or(vec![], |r| {
1009	                    r.removed.iter().map(|e| e.selector.clone()).collect()
1010	                }),
1011	                modified: diff_report.map_or(vec![], |r| {
1012	                    r.modified.iter().map(|m| m.selector.clone()).collect()
1013	                }),
1014	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
1015	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
1016	            }
1017	        }
1018	        Some(Content::Verification(v)) => EyeReportContent::Verification {
1019	            sub_goal_advanced: v.criteria_status == "met",
1020	            confidence: v.confidence,
1021	            reasoning: v.reasoning.clone(),
1022	            criteria_status: v.criteria_status.clone(),
1023	        },
1024	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
1025	            failure_type: e.failure_type.clone(),
1026	            description: e.description.clone(),
1027	            recovery_actions: e.recovery_actions.clone(),
1028	            should_retry: e.should_retry,
1029	            max_retries: e.max_retries as u32,
1030	        },
1031	        None => return None,
1032	    };
1033	
1034	    Some(ans_core::signal::EyeReport {
1035	        eye_name,
1036	        timestamp: chrono::Utc::now(),
1037	        confidence: proto.confidence,
1038	        goal_relevance: proto.goal_relevance,
1039	        content,
1040	    })
1041	}
