1057	                v.visible_elements.len(),
1058	                v.overlays.len(),
1059	                v.page_type
1060	            )
1061	        }
1062	        Some(Content::Diff(d)) => {
1063	            format!(
1064	                "Diff: {}% visual change",
1065	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
1066	            )
1067	        }
1068	        Some(Content::Verification(v)) => {
1069	            format!(
1070	                "Verify: {} (confidence={:.0}%)",
1071	                v.criteria_status,
1072	                v.confidence * 100.0
1073	            )
1074	        }
1075	        Some(Content::Error(e)) => {
