1	//! DOM distillation engine.
2	//!
3	//! Walks the raw CDP DOM tree (from `DOM.getDocument`) and produces a
4	//! [`DistilledPage`] in one pass. Mode controls what gets stripped vs. kept.
5	//!
6	//! Pipeline: walk → filter → annotate → segment → detect distractions.
7	
8	use std::collections::HashMap;
9	
10	use ans_core::distill::{
11	    DistillMode, DistilledElement, DistilledPage, InteractiveElement, InteractiveType,
12	};
13	use ans_core::immune::{DistractionFlag, DistractionKind, ImmuneAction};
14	use serde_json::Value as Json;
15	
16	use crate::semantic;
17	
18	/// Maximum elements to extract from any page. Pages exceeding this
19	/// are truncated to prevent memory exhaustion on DOM bombs.
20	const MAX_ELEMENTS: usize = 5000;
21	
22	/// HTML tags that represent interactive elements.
23	const INTERACTIVE_TAGS: &[&str] = &[
24	    "a", "button", "input", "select", "textarea", "option", "form",
25	];
26	
27	/// Tags that are purely presentational — always stripped in `TextOnly` mode,
28	/// and only kept in other modes if they contain text.
29	const PRESENTATIONAL_TAGS: &[&str] = &[
30	    "script", "style", "noscript", "svg", "path", "meta", "link", "br", "hr",
31	];
32	
33	/// The distiller. Stateless — created once, reused across pages.
34	pub struct Distiller;
35	
36	impl Distiller {
37	    /// Process raw CDP `DOM.getDocument` JSON into a [`DistilledPage`].
38	    ///
39	    /// `raw_dom` is the full response value from the CDP command.
40	    /// `mode` controls the distillation aggressiveness.
41	    #[must_use] 
42	    pub fn process(
43	        &self,
44	        raw_dom: &Json,
45	        mode: DistillMode,
46	        url: &str,
47	        title: &str,
48	    ) -> DistilledPage {
49	        let root = &raw_dom["root"];
50	        let mut ctx = WalkContext::new(mode);
51	
52	        walk_node(root, 0, &mut ctx);
53	
54	        // Segment into semantic blocks
55	        let semantic_blocks = semantic::segment_blocks(&ctx.elements);
56	
57	        // Detect distractions from semantic blocks
58	        let distraction_flags = detect_distractions(&semantic_blocks, &ctx.elements);
59	
60	        DistilledPage {
61	            mode,
62	            url: url.to_string(),
63	            title: title.to_string(),
64	            elements: ctx.elements,
65	            interactive: ctx.interactive,
66	            semantic_blocks,
67	            distraction_flags,
68	            timestamp: chrono::Utc::now(),
69	        }
70	    }
71	}
72	
73	/// Mutable state accumulated during a single tree walk.
74	struct WalkContext {
75	    mode: DistillMode,
76	    elements: Vec<DistilledElement>,
77	    interactive: Vec<InteractiveElement>,
78	    /// Maps CDP nodeId → index into `elements`. Not persisted; used only
79	    /// during the walk to resolve child references.
80	    node_map: HashMap<i32, usize>,
81	}
82	
83	impl WalkContext {
84	    fn new(mode: DistillMode) -> Self {
85	        Self {
86	            mode,
87	            elements: Vec::with_capacity(512),
88	            interactive: Vec::with_capacity(64),
89	            node_map: HashMap::with_capacity(512),
90	        }
91	    }
92	
93	    fn at_capacity(&self) -> bool {
94	        self.elements.len() >= MAX_ELEMENTS
95	    }
96	}
97	
98	/// Recursively walk a CDP DOM node and its children.
99	fn walk_node(node: &Json, depth: usize, ctx: &mut WalkContext) {
100	    if ctx.at_capacity() {
101	        return;
102	    }
103	
104	    let node_type = node["nodeType"].as_i64().unwrap_or(-1);
105	
106	    match node_type {
107	        1 => walk_element(node, depth, ctx),
108	        3 => {
109	            // Text node — its value is accumulated by the parent element walker,
110	            // so we don't create a separate entry unless there's no parent context.
111	        }
112	        _ => {
113	            // Document (9), DocumentType (10), or unknown — recurse into children
114	            if let Some(children) = node["children"].as_array() {
115	                for child in children {
116	                    walk_node(child, depth + 1, ctx);
117	                }
118	            }
119	        }
120	    }
121	}
122	
123	/// Process an element node (nodeType=1).
124	fn walk_element(node: &Json, depth: usize, ctx: &mut WalkContext) {
125	    let tag = node["nodeName"]
126	        .as_str()
127	        .unwrap_or("unknown")
128	        .to_lowercase();
129	
130	    // Always skip presentational tags
131	    if PRESENTATIONAL_TAGS.contains(&tag.as_str()) {
132	        return;
133	    }
134	
135	    let attributes = parse_attributes(node);
136	    let role = infer_role(&tag, &attributes);
137	    let text = collect_text(node, &tag);
138	    let is_visible = is_element_visible(&attributes, node);
139	
140	    // Decide whether to keep this element based on mode
141	    let is_interactive = INTERACTIVE_TAGS.contains(&tag.as_str());
142	
143	    let keep = match ctx.mode {
144	        DistillMode::TextOnly => {
145	            // Keep only elements that have visible text content
146	            !text.trim().is_empty()
147	        }
148	        DistillMode::InputFields => {
149	            // Keep text-bearing AND interactive elements
150	            !text.trim().is_empty() || is_interactive
151	        }
152	        DistillMode::AllFields => {
153	            // Keep everything (except presentational tags, already filtered)
154	            true
155	        }
156	    };
157	
158	    if !keep {
159	        // Still recurse into children — they might be keepable
160	        if let Some(children) = node["children"].as_array() {
161	            for child in children {
162	                walk_node(child, depth + 1, ctx);
163	            }
164	        }
165	        return;
166	    }
167	
168	    // Walk children first so we know their indices
169	    let child_start = ctx.elements.len();
170	    if let Some(children) = node["children"].as_array() {
171	        for child in children {
172	            walk_node(child, depth + 1, ctx);
173	        }
174	    }
175	    let child_end = ctx.elements.len();
176	
177	    let children: Vec<usize> = (child_start..child_end).collect();
178	
179	    let node_id = node["nodeId"].as_i64().unwrap_or(-1) as i32;
180	
181	    let element = DistilledElement {
182	        tag,
183	        text,
184	        attributes,
185	        role,
186	        is_visible,
187	        bounding_box: None, // Bounding boxes require separate CDP calls (Phase 2 refinement)
188	        children,
189	    };
190	
191	    if ctx.at_capacity() {
192	        return;
193	    }
194	
195	    let idx = ctx.elements.len();
196	    ctx.node_map.insert(node_id, idx);
197	    ctx.elements.push(element);
198	
199	    // Identify interactive elements
200	    if is_interactive {
201	        let el = &ctx.elements[idx];
202	        if let Some(interactive) = build_interactive(el, idx) {
203	            ctx.interactive.push(interactive);
204	        }
205	    }
206	}
207	
208	/// Parse CDP attributes array `["key1", "val1", "key2", "val2"]` into a `HashMap`.
209	fn parse_attributes(node: &Json) -> HashMap<String, String> {
210	    let mut map = HashMap::new();
211	    if let Some(arr) = node["attributes"].as_array() {
212	        let mut i = 0;
213	        while i + 1 < arr.len() {
214	            if let (Some(k), Some(v)) = (arr[i].as_str(), arr[i + 1].as_str()) {
215	                map.insert(k.to_string(), v.to_string());
216	            }
217	            i += 2;
218	        }
219	    }
220	    map
221	}
222	
223	/// Infer an ARIA role from tag name and explicit role attribute.
224	fn infer_role(tag: &str, attrs: &HashMap<String, String>) -> Option<String> {
225	    // Explicit role attribute takes precedence
226	    if let Some(role) = attrs.get("role") {
227	        if !role.is_empty() {
228	            return Some(role.clone());
229	        }
230	    }
231	
232	    // Implicit roles from HTML spec
233	    match tag {
234	        "a" if attrs.get("href").is_some() => Some("link".into()),
235	        "button" => Some("button".into()),
236	        "nav" => Some("navigation".into()),
237	        "main" => Some("main".into()),
238	        "form" => Some("form".into()),
239	        "input" => {
240	            let input_type = attrs.get("type").map_or("text", std::string::String::as_str);
241	            match input_type {
242	                "checkbox" => Some("checkbox".into()),
243	                "radio" => Some("radio".into()),
244	                "submit" | "button" => Some("button".into()),
245	                _ => Some("textbox".into()),
246	            }
247	        }
248	        "select" => Some("combobox".into()),
249	        "textarea" => Some("textbox".into()),
250	        "img" => Some("img".into()),
251	        "h1" | "h2" | "h3" | "h4" | "h5" | "h6" => Some("heading".into()),
252	        "ul" | "ol" => Some("list".into()),
253	        "li" => Some("listitem".into()),
254	        "table" => Some("table".into()),
255	        "header" => Some("banner".into()),
256	        "footer" => Some("contentinfo".into()),
257	        "aside" => Some("complementary".into()),
258	        _ => None,
259	    }
260	}
261	
262	/// Collect visible text from an element's subtree.
263	fn collect_text(node: &Json, _tag: &str) -> String {
264	    let mut buf = String::new();
265	    collect_text_recursive(node, &mut buf);
266	    // Normalize whitespace
267	    let result: String = buf.split_whitespace().collect::<Vec<_>>().join(" ");
268	    // Truncate for memory safety — use char_indices to avoid
269	    // slicing in the middle of a multi-byte UTF-8 character.
270	    if result.len() > 500 {
271	        let truncate_at = result
272	            .char_indices()
273	            .take_while(|&(i, _)| i < 500)
274	            .map(|(i, c)| i + c.len_utf8())
275	            .last()
276	            .unwrap_or(500);
277	        result[..truncate_at.min(result.len())].to_string()
278	    } else {
279	        result
280	    }
281	}
282	
283	fn collect_text_recursive(node: &Json, buf: &mut String) {
284	    let node_type = node["nodeType"].as_i64().unwrap_or(-1);
285	    match node_type {
286	        3 => {
287	            // Text node
288	            if let Some(text) = node["nodeValue"].as_str() {
289	                buf.push_str(text);
290	            }
291	        }
292	        1 => {
293	            // Element node — recurse into children, add space between elements
294	            if let Some(children) = node["children"].as_array() {
295	                for child in children {
296	                    collect_text_recursive(child, buf);
297	                    buf.push(' ');
298	                }
299	            }
300	        }
301	        _ => {
302	            if let Some(children) = node["children"].as_array() {
303	                for child in children {
304	                    collect_text_recursive(child, buf);
305	                }
306	            }
307	        }
308	    }
309	}
310	
311	/// Heuristic visibility check based on common hidden patterns.
312	fn is_element_visible(attrs: &HashMap<String, String>, _node: &Json) -> bool {
313	    let style = attrs.get("style").map_or("", std::string::String::as_str);
314	    let hidden = attrs.get("hidden");
315	    let aria_hidden = attrs.get("aria-hidden");
316	    let class = attrs.get("class").map_or("", std::string::String::as_str);
317	
318	    if hidden.is_some() {
319	        return false;
320	    }
321	    if aria_hidden.is_some_and(|v| v == "true") {
322	        return false;
323	    }
324	    if style.contains("display: none")
325	        || style.contains("display:none")
326	        || style.contains("visibility: hidden")
327	        || style.contains("visibility:hidden")
328	    {
329	        return false;
330	    }
331	    if class.contains("hidden") || class.contains("sr-only") || class.contains("d-none") {
332	        return false;
333	    }
334	
335	    true
336	}
337	
338	/// Build an [`InteractiveElement`] from a distilled element if it's interactive.
339	fn build_interactive(el: &DistilledElement, _idx: usize) -> Option<InteractiveElement> {
340	    let element_type = match el.tag.as_str() {
341	        "a" => InteractiveType::Link,
342	        "button" => InteractiveType::Button,
343	        "input" => {
344	            let input_type = el
345	                .attributes
346	                .get("type")
347	                .map_or("text", std::string::String::as_str);
348	            match input_type {
349	                "checkbox" => InteractiveType::Checkbox,
350	                "radio" => InteractiveType::Radio,
351	                "submit" | "button" => InteractiveType::Button,
352	                _ => InteractiveType::Input,
353	            }
354	        }
355	        "select" | "option" => InteractiveType::Select,
356	        "textarea" => InteractiveType::Textarea,
357	        _ => return None,
358	    };
359	
360	    let selector = build_selector(el);
361	
362	    Some(InteractiveElement {
363	        selector,
364	        element_type,
365	        label: el.text.clone(),
366	        placeholder: el.attributes.get("placeholder").cloned(),
367	        current_value: el.attributes.get("value").cloned(),
368	        is_visible: el.is_visible,
369	        is_enabled: !el.attributes.contains_key("disabled"),
370	        bounding_box: el.bounding_box,
371	    })
372	}
373	
374	/// Build a CSS selector string for an element.
375	fn build_selector(el: &DistilledElement) -> String {
376	    if let Some(id) = el.attributes.get("id") {
377	        if !id.is_empty() && is_valid_css_id(id) {
378	            return format!("#{id}");
379	        }
380	    }
381	
382	    // Build tag + class selector
383	    let mut sel = el.tag.clone();
384	    if let Some(class) = el.attributes.get("class") {
385	        let classes: Vec<&str> = class
386	            .split_whitespace()
387	            .filter(|c| is_valid_css_class(c))
388	            .take(2)
389	            .collect();
390	        if !classes.is_empty() {
391	            sel.push('.');
392	            sel.push_str(&classes.join("."));
393	        }
394	    }
395	    sel
396	}
397	
398	fn is_valid_css_id(id: &str) -> bool {
399	    id.chars()
400	        .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
401	}
402	
403	fn is_valid_css_class(class: &str) -> bool {
404	    !class.is_empty()
405	        && class
406	            .chars()
407	            .all(|c| c.is_alphanumeric() || c == '-' || c == '_')
408	}
409	
410	/// Detect distractions by scanning semantic blocks for ad/cookie/popup patterns.
411	fn detect_distractions(
412	    blocks: &[ans_core::distill::SemanticBlock],
413	    elements: &[DistilledElement],
414	) -> Vec<DistractionFlag> {
415	    let mut flags = Vec::new();
416	
417	    for block in blocks {
418	        let (kind, action) = match block.block_type {
419	            ans_core::distill::BlockType::Ad => (DistractionKind::Ad, ImmuneAction::Suppress),
420	            ans_core::distill::BlockType::CookieBanner => {
421	                (DistractionKind::CookieBanner, ImmuneAction::Dismiss)
422	            }
423	            ans_core::distill::BlockType::Popup => (DistractionKind::Popup, ImmuneAction::Dismiss),
424	            _ => continue,
425	        };
426	
427	        // Build selector from the first element in the block
428	        let selector = block
429	            .element_indices
430	            .first()
431	            .and_then(|&i| elements.get(i))
432	            .map(build_selector)
433	            .unwrap_or_default();
434	
435	        flags.push(DistractionFlag {
436	            kind,
437	            element_selector: selector,
438	            confidence: 0.8,
439	            suggested_action: action,
440	        });
441	    }
442	
443	    flags
444	}
